!function(){"use strict";const e=document.getElementById("blogPostContent"),t=document.getElementById("blogPostTitle"),n=document.getElementById("relatedPosts");if(!e)return;const o=new URLSearchParams(window.location.search),a=parseInt(o.get("id"));window.blogPosts;function i(e){return new Date(e).toLocaleDateString("en-IE",{day:"numeric",month:"long",year:"numeric"})}!function o(){const l=window.blogPosts||[];if(!l.length)return void setTimeout(o,200);const s=l.find(e=>e.id===a);if(s){if(t&&(t.textContent=s.title),document.title=s.title+" | SFI Blog",e.innerHTML=`\n        <div class="container" style="max-width:800px;margin:0 auto;padding:40px 20px">\n            <a href="blog.html" class="blog-back-link">← Back to Blog</a>\n            <div class="blog-post-header">\n                <span class="blog-tag">${s.category}</span>\n                <h1>${s.title}</h1>\n                <div class="blog-meta">${i(s.date)} · ${s.readTime} read · By ${s.author}</div>\n            </div>\n            <div class="blog-post-hero" style="background-image:url('${s.image}')"></div>\n            <div class="blog-post-body">\n                <p class="blog-lead">${s.excerpt}</p>\n                <p>This article is coming soon. We're working on creating comprehensive, expert content to help you perform at your best. Check back soon for the full article!</p>\n                <p>In the meantime, browse our <a href="shop.html">product range</a> or <a href="contact.html">contact us</a> for personalised advice.</p>\n            </div>\n        </div>`,n){const e=l.filter(e=>e.id!==a).slice(0,3);n.innerHTML=e.map(e=>`\n            <article class="blog-card">\n                <a href="blog-post.html?id=${e.id}">\n                    <div class="blog-card-img" style="background-image:url('${e.image}')"></div>\n                    <div class="blog-card-body">\n                        <span class="blog-tag">${e.category}</span>\n                        <h3>${e.title}</h3>\n                        <div class="blog-meta">${i(e.date)} · ${e.readTime} read</div>\n                    </div>\n                </a>\n            </article>\n        `).join("")}}else e.innerHTML='<div style="text-align:center;padding:60px"><h2>Post not found</h2><p><a href="blog.html">← Back to Blog</a></p></div>'}()}();